#include <iostream>
#include <climits>

using namespace std;

/**
 * Function to find the second largest distinct element in an array.
 * Returns INT_MIN if no such element exists.
 */
int findSecondLargest(int arr[], int n) {
    if (n < 2) {
        return INT_MIN;
    }

    int first = INT_MIN;
    int second = INT_MIN;

    for (int i = 0; i < n; i++) {
        // If current element is greater than first, update both first and second
        if (arr[i] > first) {
            second = first;
            first = arr[i];
        }
        // If current element is between first and second, update second
        else if (arr[i] > second && arr[i] < first) {
            second = arr[i];
        }
    }

    return second;
}

int main() {
    int n;
    if (!(cin >> n)) return 0;

    if (n <= 0) {
        cout << INT_MIN << endl;
        return 0;
    }

    int* arr = new int[n];
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }

    int result = findSecondLargest(arr, n);
    cout << result << endl;

    delete[] arr;
    return 0;
}
